#include <stdio.h>
#include <omp.h>

void 
findK(	long height,
		knode *knodesD,
		long knodes_elem,
		record *recordsD,

		long *currKnodeD,
		long *offsetD,
		int *keysD, 
		record *ansD,
        int order,
        int count)
{
    int bid;

    #pragma omp parallel for private(bid)
    for (bid = 0; bid < count; bid++) {
        int i, thid;
        for (i = 0; i < height; i++) {
            #pragma omp parallel for private(thid)
            for (thid = 0; thid < order; thid++) {
                if ((knodesD[currKnodeD[bid]].keys[thid]) <= keysD[bid] && (knodesD[currKnodeD[bid]].keys[thid+1] > keysD[bid])) {
                    if(knodesD[offsetD[bid]].indices[thid] < knodes_elem){
                        #pragma omp critical
                        {
                            offsetD[bid] = knodesD[offsetD[bid]].indices[thid];
                        }
                    }
                }
            }
            #pragma omp barrier
            if(omp_get_thread_num() == 0){
                currKnodeD[bid] = offsetD[bid];
            }
            #pragma omp barrier
        }

        #pragma omp parallel for private(thid)
        for (thid = 0; thid < order; thid++) {
            if(knodesD[currKnodeD[bid]].keys[thid] == keysD[bid]){
                ansD[bid].value = recordsD[knodesD[currKnodeD[bid]].indices[thid]].value;
            }
        }
    }
}

